package ru.memearena.scout.infrastructure; import org.springframework.data.domain.*; import org.springframework.data.jpa.repository.*; import ru.memearena.scout.domain.*; import java.util.*; public interface MemePredictionRepository extends JpaRepository<MemePrediction,UUID>{ boolean existsByUserIdAndMemeId(UUID u,UUID m); Optional<MemePrediction> findByUserIdAndMemeId(UUID u,UUID m); List<MemePrediction> findByMemeIdAndStatusOrderByUserIdAscPredictedAtAsc(UUID memeId,PredictionStatus s); Page<MemePrediction> findByUserId(UUID userId,Pageable p); Page<MemePrediction> findByUserIdAndStatus(UUID userId,PredictionStatus status,Pageable p); @Query("select distinct p.memeId from MemePrediction p where p.status=ru.memearena.scout.domain.PredictionStatus.PENDING") List<UUID> pendingMemeIds(); }
